#include <stdio.h>
#include <limits.h>

int main() {
    int r, c;
    scanf("%d %d", &r, &c);

    int grid[500][500];
    int dp[500][500];

    for (int i = 0; i < r; i++) {
        for (int j = 0; j < c; j++) {
            scanf("%d", &grid[i][j]);
            dp[i][j] = INT_MIN;
        }
    }
    for (int j = 0; j < c; j++) {
        dp[0][j] = grid[0][j];
    }
    for (int i = 1; i < r; i++) {
        for (int j = 0; j < c; j++) {
            int best = dp[i-1][j];
            if (j > 0 && dp[i-1][j-1] > best)
                best = dp[i-1][j-1];
            if (j + 1 < c && dp[i-1][j+1] > best)
                best = dp[i-1][j+1];

            dp[i][j] = best + grid[i][j];
        }
    }

    int result = dp[r-1][0];
    for (int j = 1; j < c; j++) {
        if (dp[r-1][j] > result)
            result = dp[r-1][j];
    }

    printf("%d\n", result);
    return 0;
}
